it("should let a live cell with 2 or 3 neighbors survive", () => {
  // Gen 0:        Gen 1:
  //  ###           .#.
  //  ...     →     .#.
  //  .#.           ...
  // The center cell (1,1) has 3 live neighbors and stays alive.
  const gen0: Cell[] = [[0, 0], [1, 0], [2, 0], [1, 2]];
  expect(nextGeneration(gen0)).toContainEqual([1, 1]);
});
